SELECT

FROM t_member_credit_score_type t
LEFT JOIN t_member m ON m.id = t.user_id
LEFT JOIN t_credit_score_type_config cfg
    ON cfg.type = t.type AND cfg.subtype = t.subtype AND cfg.is_deleted = 0

    t.is_deleted = 0

        AND t.user_id = #{userId}


        AND m.idno LIKE CONCAT('%', #{idno}, '%')


        AND m.lianghao LIKE CONCAT('%', #{lianghao}, '%')


        AND t.type = #{type}


        AND t.subtype = #{subtype}



    ORDER BY ${orderBy}


    ORDER BY t.update_time DESC, t.id DESC


    LIMIT #{pageNo}, #{pageSize}

SELECT COUNT(1)
FROM t_member_credit_score_type t
LEFT JOIN t_member m ON m.id = t.user_id
WHERE t.is_deleted = 0

    AND t.user_id = #{userId}


    AND m.idno LIKE CONCAT('%', #{idno}, '%')


    AND m.lianghao LIKE CONCAT('%', #{lianghao}, '%')


    AND t.type = #{type}


    AND t.subtype = #{subtype}
